function firstUniqChar(s) {
  const cnt = {};
  for (let i = 0; i < s.length; i++) cnt[s[i]] = (cnt[s[i]] || 0) + 1;
  for (let i = 0; i < s.length; i++) if (cnt[s[i]] === 1) return i;
  return -1;
}

