function groupAnagrams(words) {
  const m = new Map();
  for (let i = 0; i < words.length; i++) {
    const w = words[i];
    const key = [...w].sort().join('');
    if (!m.has(key)) m.set(key, []);
    m.get(key).push(w);
  }
  return [...m.values()];
}

